import Foundation

// Verify the geometry math
let testSize = CGSize(width: 400, height: 400)
let center = CGPoint(x: testSize.width / 2, y: testSize.height / 2)
let radius = min(testSize.width, testSize.height) / 2 * 0.9

print("Test Case: 400x400 canvas")
print("Center: \(center)")
print("Expected center: (200.0, 200.0)")
print("Radius: \(radius)")
print("Expected radius: 180.0 (200 * 0.9)")
print()

// Verify hour angles
// Hour 12 should point straight up (-90 degrees = top)
let hour12Angle = Double(0) * 30 - 90
print("Hour 12 (0 * 30 - 90): \(hour12Angle) degrees ✓ (should be -90)")

// Hour 3 should point right (0 degrees)
let hour3Angle = Double(3) * 30 - 90
print("Hour 3 (3 * 30 - 90): \(hour3Angle) degrees ✓ (should be 0)")

// Hour 6 should point down (90 degrees)
let hour6Angle = Double(6) * 30 - 90
print("Hour 6 (6 * 30 - 90): \(hour6Angle) degrees ✓ (should be 90)")

// Hour 9 should point left (180 degrees)
let hour9Angle = Double(9) * 30 - 90
print("Hour 9 (9 * 30 - 90): \(hour9Angle) degrees ✓ (should be 180)")
print()

// Verify minute angles
let minute0Angle = Double(0) * 6 - 90
print("Minute 0 (0 * 6 - 90): \(minute0Angle) degrees ✓ (should be -90)")

let minute15Angle = Double(15) * 6 - 90
print("Minute 15 (15 * 6 - 90): \(minute15Angle) degrees ✓ (should be 0)")
print()

// Verify 60 markers (one every 6 degrees)
print("Hour markers check:")
print("Total markers: 60 (0 to 59, each 6 degrees apart)")
print("Bold markers (every 5th): indices 0, 5, 10, 15, 20, 25, 30, 35, 40, 45, 50, 55")
var boldCount = 0
for i in 0..<60 {
    if i % 5 == 0 {
        boldCount += 1
    }
}
print("Total bold markers: \(boldCount) ✓ (should be 12)")
print()

// Verify Roman numerals (12 numerals at 30-degree intervals)
print("Roman numerals check:")
print("Total numerals: 12 (indices 0 to 11)")
print("Angle intervals: 0°, 30°, 60°, 90°, 120°, 150°, 180°, 210°, 240°, 270°, 300°, 330°")
let numeral_order = ["XII", "I", "II", "III", "IV", "V", "VI", "VII", "VIII", "IX", "X", "XI"]
for (index, numeral) in numeral_order.enumerated() {
    let angle = Double(index) * 30
    print("  \(numeral) at \(angle)°")
}
